const body = $input.first().json.body || $input.first().json;
// Handle Typeform, raw array, or single survey batch
let responses = [];
if (Array.isArray(body.responses)) { responses = body.responses; }
else if (Array.isArray(body)) { responses = body; }
else if (body.form_response) { responses = [body.form_response]; } // Typeform webhook
else { responses = [body]; }

const survey = {
  id:        body.survey_id   || `surv_${Date.now()}`,
  title:     body.survey_name || body.title || 'Untitled Survey',
  total:     responses.length,
  date:      new Date().toISOString().slice(0,10),
  responses: responses.slice(0,200).map((r,i) => ({
    index:   i,
    segment: r.segment || r.customer_segment || r.plan || 'unknown',
    answers: r.answers || r.fields || r,
  })),
};
return [{ json: survey }];

