const survey = $('Normalise Survey Data').first().json;
let ai;
try { ai = JSON.parse(($input.first().json.message?.content||'{}').replace(/```json|```/g,'').trim()); }
catch { ai = {}; }
return [{ json: { survey_id: survey.id, title: survey.title, total_responses: survey.total, analysis_date: survey.date, ...ai } }];

